import{_ as o,o as n,c as t,a2 as a}from"./chunks/framework.ufzXw1qY.js";const g=JSON.parse('{"title":"OpenSIN-AI Code — Python Agent Development Platform","description":"","frontmatter":{},"headers":[],"relativePath":"guide/opensin-ai-code.md","filePath":"guide/opensin-ai-code.md"}'),i={name:"guide/opensin-ai-code.md"};function s(r,e,p,l,d,c){return n(),t("div",null,[...e[0]||(e[0]=[a(`<h1 id="opensin-ai-code-—-python-agent-development-platform" tabindex="-1">OpenSIN-AI Code — Python Agent Development Platform <a class="header-anchor" href="#opensin-ai-code-—-python-agent-development-platform" aria-label="Permalink to &quot;OpenSIN-AI Code — Python Agent Development Platform&quot;">​</a></h1><blockquote><p><strong>Update April 2026:</strong> The standalone <code>OpenSIN-AI/opensin-ai-code</code> repository has been consolidated into the OpenSIN monorepo as <code>opensin_agent_platform/</code>.</p><p><strong>New location:</strong> <a href="https://github.com/OpenSIN-AI/OpenSIN/tree/main/opensin_agent_platform" target="_blank" rel="noreferrer"><code>OpenSIN-AI/OpenSIN/opensin_agent_platform</code></a></p></blockquote><p>OpenSIN-AI Code is the Python-based Agent Development Platform. It was originally shipped as its own repo; as of the April 2026 consolidation it lives inside <code>OpenSIN</code> next to the other canonical Python packages (<code>opensin_core</code>, <code>opensin_cli</code>, <code>opensin_api</code>, <code>opensin_sdk</code>).</p><blockquote><p><strong>Status:</strong> Preserved as reference material under <code>OpenSIN/opensin_agent_platform/</code>. Not yet wired into the <code>OpenSIN</code> build. The follow-up rationalization will port genuinely useful logic into <code>opensin_core</code> and retire the folder. See <a href="https://github.com/OpenSIN-AI/OpenSIN/blob/main/opensin_agent_platform/README.md" target="_blank" rel="noreferrer"><code>opensin_agent_platform/README.md</code></a> for the plan.</p></blockquote><h2 id="why-consolidated" tabindex="-1">Why consolidated <a class="header-anchor" href="#why-consolidated" aria-label="Permalink to &quot;Why consolidated&quot;">​</a></h2><ul><li>The standalone repo advertised <code>pip install opensin-ai-code</code> but shipped no <code>pyproject.toml</code>, so the install path never worked.</li><li>It duplicated ground already covered by <code>opensin_core</code> in the <code>OpenSIN</code> repo (both define <code>hooks</code>, <code>plugins</code>, <code>skills</code>, QueryEngine, Tool/Permission/Memory systems).</li></ul><p>Full rationale: <a href="https://github.com/OpenSIN-AI/OpenSIN-overview/blob/main/docs/CONSOLIDATION-2026-04.md" target="_blank" rel="noreferrer">OpenSIN-overview consolidation report</a>.</p><h2 id="getting-the-source" tabindex="-1">Getting the source <a class="header-anchor" href="#getting-the-source" aria-label="Permalink to &quot;Getting the source&quot;">​</a></h2><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> clone</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> https://github.com/OpenSIN-AI/OpenSIN.git</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">cd</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> OpenSIN/opensin_agent_platform</span></span></code></pre></div><p>All 100 Python files and 26 subsystem packages are preserved exactly as they were in the standalone repo.</p><h2 id="see-also" tabindex="-1">See also <a class="header-anchor" href="#see-also" aria-label="Permalink to &quot;See also&quot;">​</a></h2><ul><li><a href="https://github.com/OpenSIN-AI/OpenSIN" target="_blank" rel="noreferrer">OpenSIN Repository</a> — the canonical Python monorepo</li><li><a href="./opensin-ai-agent-features.html">OpenSIN-AI Code Agent Comparison</a></li><li><a href="https://github.com/OpenSIN-AI/OpenSIN-overview/blob/main/docs/opensin-ai-agent-feature-spec.md" target="_blank" rel="noreferrer">OpenSIN-AI Agent Feature Spec</a></li><li><a href="https://github.com/OpenSIN-AI/OpenSIN-overview/blob/main/docs/CANONICAL-REPOS.md" target="_blank" rel="noreferrer">Canonical Repos Map</a></li></ul>`,12)])])}const m=o(i,[["render",s]]);export{g as __pageData,m as default};
